  1	import { type ComponentProps, type ForwardedRef, forwardRef, useMemo } from 'react';
  2	import { getResourceUrl } from 'src/modules/Providers/utils/helpers/getResourceUrl';
  3	
  4	import { ExternalLink } from '@components/common/ExternalLink/ExternalLink';
  5	import Select from '@components/common/Select';
  6	import {
  7	  NetworkMapModelGroupVersionKind,
  8	  NetworkMapModelRef,
  9	  type V1beta1NetworkMap,
 10	} from '@kubev2v/types';
 11	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 12	import {
 13	  EmptyState,
 14	  EmptyStateBody,
 15	  EmptyStateVariant,
 16	  SelectList,
 17	  SelectOption,
 18	  Title,
 19	} from '@patternfly/react-core';
 20	import { getName } from '@utils/crds/common/selectors';
 21	import { isEmpty } from '@utils/helpers';
 22	import { useForkliftTranslation } from '@utils/i18n';
 23	
 24	type NetworkMapSelectProps = Pick<ComponentProps<typeof Select>, 'onSelect' | 'status'> & {
 25	  id: string;
 26	  value: string;
 27	  namespace: string;
 28	  includeOwnerReferenced?: boolean;
 29	  testId?: string;
 30	};
 31	
 32	const NetworkMapSelect = (
 33	  {
 34	    id,
 35	    includeOwnerReferenced = false,
 36	    namespace,
 37	    onSelect,
 38	    status,
 39	    testId,
 40	    value,
 41	  }: NetworkMapSelectProps,
 42	  ref: ForwardedRef<HTMLButtonElement>,
 43	) => {
 44	  const { t } = useForkliftTranslation();
 45	  const [allNetworkMaps] = useK8sWatchResource<V1beta1NetworkMap[]>({
 46	    groupVersionKind: NetworkMapModelGroupVersionKind,
 47	    isList: true,
 48	    namespace,
 49	  });
 50	
 51	  const networkMapsListUrl = getResourceUrl({
 52	    namespace,
 53	    reference: NetworkMapModelRef,
 54	  });
 55	
 56	  // Filter out network maps that have ownerReferences unless includeOwnerReferenced is true
 57	  const networkMaps = useMemo(() => {
 58	    if (!allNetworkMaps) {
 59	      return [];
 60	    }
 61	
 62	    if (includeOwnerReferenced) {
 63	      return allNetworkMaps;
 64	    }
 65	
 66	    return allNetworkMaps.filter((networkMap) => {
 67	      return isEmpty(networkMap.metadata?.ownerReferences);
 68	    });
 69	  }, [allNetworkMaps, includeOwnerReferenced]);
 70	
 71	  const emptyState = (
 72	    <EmptyState variant={EmptyStateVariant.xs}>
 73	      <Title headingLevel="h4" size="md">
 74	        {t('You do not have any network maps without owner references.')}
 75	      </Title>
 76	      <EmptyStateBody>
 77	        <ExternalLink href={`${networkMapsListUrl}/~new`} isInline>
 78	          {t('Create a network map without an owner')}
 79	        </ExternalLink>
 80	      </EmptyStateBody>
 81	    </EmptyState>
 82	  );
 83	
 84	  return (
 85	    <Select
 86	      id={id}
 87	      ref={ref}
 88	      value={value}
 89	      status={status}
 90	      onSelect={onSelect}
 91	      placeholder={t('Select network map')}
 92	      testId={testId}
 93	    >
 94	      <SelectList>
 95	        {isEmpty(networkMaps)
 96	          ? emptyState
 97	          : networkMaps.map((networkMap) => {
 98	              const networkMapName = getName(networkMap);
 99	
100	              return (
101	                <SelectOption key={networkMapName} value={networkMap}>
102	                  {networkMapName}
103	                </SelectOption>
104	              );
105	            })}
106	      </SelectList>
107	    </Select>
108	  );
109	};
110	
111	export default forwardRef(NetworkMapSelect);

